org.machanism.machai.ai.manager.GenAIProvider provider = /* ... */;
provider.addTool(
  "echo",
  "Returns the provided message.",
  (java.lang.Object[] args) -> {
    com.fasterxml.jackson.databind.JsonNode props = (com.fasterxml.jackson.databind.JsonNode) args[0];
    return props.has("message") ? props.get("message").asText() : "";
  },
  "message:string:optional:Message to echo back"
);

